def find_common_chars(*strings):
    if not strings:
        return []

    # İlk dizenin karakterlerini bir küme (hash map tabanlı bir yapı) olarak başlat
    # Bu küme, şimdiye kadar ortak olan karakterleri tutacak.
    common_chars_set = set(strings[0])

    # Geri kalan dizeler üzerinde döngü yap
    for s in strings[1:]:
        # Mevcut ortak karakterler kümesi ile geçerli dizenin karakter kümesinin kesişimini bul
        # Bu, ortak karakterler kümesini günceller.
        common_chars_set = common_chars_set.intersection(set(s))

        # Eğer ortak karakter kümesi boşalırsa, daha fazla ortak karakter olamaz
        if not common_chars_set:
            break

    # Ortak karakterler kümesini bir listeye dönüştür ve döndür
    return list(common_chars_set)
